import{_ as o,o as e,c as t,a2 as l}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"G02: 董事高階經理人異動審計","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/經營組備份_20260501/G02_董事高階經理人異動審計_績效管理專家.md","filePath":"32Ｑ題本＿重要/經營組備份_20260501/G02_董事高階經理人異動審計_績效管理專家.md"}'),n={name:"32Ｑ題本＿重要/經營組備份_20260501/G02_董事高階經理人異動審計_績效管理專家.md"};function i(s,r,a,_,g,c){return e(),t("div",null,[...r[0]||(r[0]=[l('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="g02-董事高階經理人異動審計" tabindex="-1">G02: 董事高階經理人異動審計 <a class="header-anchor" href="#g02-董事高階經理人異動審計" aria-label="Permalink to &quot;G02: 董事高階經理人異動審計&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-G02</li><li><strong>題目：</strong> 董事會與高階經理人近三年是否有非正常異動？這對公司目前經營決策與管理穩定度有何影響？</li><li><strong>推薦專家：</strong> 績效管理專家 (<code>hr-performance-reviewer</code>)</li><li><strong>推薦理由：</strong> 專精於「組織行為」與「治理結構審計」。具備識別權力中樞異動異常訊號的能力，能區分「正常退休/階隊接班」與「內部鬥爭/責任規避」。能從人事異動中讀取企業獲利轉折點或誠信紅線。</li><li><strong>意圖：</strong> 執行「組織權力穩定性與治理誠信審計」。分析核心經營者的流動，判定是否存在「權力真空」或「管理路徑大規模偏移」，識別因核心人員撤離而引發的經營危機，為公司的「執行穩定性」提供預警。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心事實來源：MOPS (公開資訊觀測站)】</strong>：檢索「重大訊息 -&gt; 董監事及高階經理人異動」。提取精確的異動日期與官方理由（如：職務調整、屆期改選、個人生涯規劃）。</li><li><strong>【穿透校準：Annual Report (年報)】</strong>：查閱「公司治理報告 -&gt; 董事及經理人資料」。比對歷年名單，識別是否存在重要部門（如 CFO, CTO, 稽核主管）的頻繁撤換。</li><li><strong>【外部驗證：Web Search】</strong>：檢索「[公司名] 高管 離職 真相」、「[公司名] 家族內鬥」。透過第三方媒體報導識別是否有檯面下的衝突。</li></ol></li><li><strong>邏輯：</strong> 執行「人事異動頻率壓力測試」——若一年內超過三位核心經理人（含財務主管）異動，判定為「治理失靈」；執行「接班順位算則」——分析繼任者背景（內部晉升 vs 外部空降）之決策延續性。</li><li><strong>來源：</strong> <code>MOPS 重大訊息 (官定證據)</code>, <code>年度報告 (治理專章)</code>, <code>商業雜誌與深度特寫</code>, <code>LinkedIn (追蹤離職高管去向)</code></li></ul><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【核心關鍵位階審核】</strong>：智慧體<strong>必須</strong>重點鎖定：董事長、總經理、財務主管、稽核主管、研發主管。若上述位置發生異動，禁止僅以「職務調整」帶過，必須深挖具體背景。</li><li><strong>【非正常時點偵測】</strong>：分析異動是否發生在「財報發布前夕」或「重大收購案執行期」。若人事異動與股價暴跌或重訊更正同步，必須強制標註為「誠信崩潰警訊」。</li><li><strong>【接班斷代風險】</strong>：若離職者為創辦人或核心技術領袖且由「非相關領域者」接任，智慧體必須標註為「文化斷代與技術流失風險」。</li><li><strong>【描述指標】</strong>：絕對禁用「人事穩定」、「平穩過度」。必須量化為具體的「異動率 %」、「平均留任年資（高管級）」與「繼任者磨合天數」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【g02-專家答詢】績效管理專家-hr-performance-reviewer" tabindex="-1">【G02 專家答詢】績效管理專家 (hr-performance-reviewer) <a class="header-anchor" href="#【g02-專家答詢】績效管理專家-hr-performance-reviewer" aria-label="Permalink to &quot;【G02 專家答詢】績效管理專家 (hr-performance-reviewer)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「異動性質+管理衝擊」結構（例：核心經營層穩定，近期 CFO 異動為 [正常接班/內部排擠]，對財務策略 [無影響/有風險]；目前權力架構 [平衡/不穩]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：經營層長期穩定，異動均為計畫內接班，且新任者具備優異的資歷與一致的策略方向。</li><li><strong>A (良)</strong>：具備局部的高管異動，但屬於正常的績效汰換或組織擴張所需，具備成熟的接班體系。</li><li><strong>B (持平)</strong>：財務、稽核或技術核心頻繁撤換，且異動理由模糊，顯示團隊陷入治理風暴或存在潛在財務爆雷掩飾，評級為「重大治理風險」。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確標註 MOPS 重訊編號、年報 P.XXX 治理架構表。</li><li><strong>【專家評析】核心分析與洞察內容</strong>：特別關注「稽核主管」與「財務主管」的異動。這兩者的同時離職通常被視為「財報即將爆雷」或「內控失效」的全球通用紅燈訊號，專家應在此處進行最嚴厲的風險評估。</li></ul>',9)])])}const u=o(n,[["render",i]]);export{h as __pageData,u as default};
